import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const BottomNavigation = () => {
  const { t } = useTranslation();
  const location = useLocation();

  // Icons
  const {
    HiHome,
    HiOutlineClipboardList,
    HiOutlineCalendar,
    HiOutlineUser,
    HiOutlineCog
  } = require('react-icons/hi');

  // Restored original items: Home, Medicines, Availability, Profile, Settings
  const navItems = [
    { path: '/', label: t('home'), icon: HiHome },
    { path: '/medicines', label: t('medicines'), icon: HiOutlineClipboardList },
    { path: '/availability', label: t('availability'), icon: HiOutlineCalendar },
    { path: '/profile', label: t('profile'), icon: HiOutlineUser },
    { path: '/settings', label: t('settings'), icon: HiOutlineCog }
  ];

  return (
    <nav
      className="fixed bottom-0 left-0 right-0 z-50 bg-white border-t border-gray-200"
      style={{ 
        boxShadow: '0 -10px 24px rgba(2,6,23,0.08)',
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        zIndex: 9999
      }}
      role="navigation"
      aria-label="Bottom navigation"
    >
      <div className="absolute top-0 left-0 right-0 h-0.5" style={{ background: 'linear-gradient(90deg,#2563eb,#7c3aed,#10b981)' }} />

      <div
        className="flex items-center justify-center px-3 pb-[env(safe-area-inset-bottom,0px)]"
        style={{ height: 72, gap: 12 }}
      >
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path;

          return (
            <Link
              key={item.path}
              to={item.path}
              className="group relative flex flex-col items-center justify-center no-underline transition-all duration-300"
              style={{ 
                textDecoration: 'none',
                width: '64px',
                height: '56px',
                margin: '0 12px',
                borderRadius: '12px',
                background: isActive ? 'linear-gradient(135deg, #2563eb 0%, #3b82f6 50%, #1d4ed8 100%)' : 'transparent'
              }}
              aria-label={`Navigate to ${item.label}`}
            >
              <div
                className="relative flex items-center justify-center w-8 h-8 rounded-lg transition-all duration-300"
                style={{
                  transform: isActive ? 'translateY(-2px) scale(1.1)' : 'translateY(0) scale(1)',
                  filter: isActive ? 'drop-shadow(0 4px 8px rgba(37,99,235,0.3))' : 'none'
                }}
              >
                <Icon 
                  className={`text-xl transition-all duration-300 ${
                    isActive ? 'text-white' : 'text-gray-500 group-hover:text-blue-600'
                  }`}
                  style={{
                    filter: isActive ? 'drop-shadow(0 0 4px rgba(255,255,255,0.5))' : 'none'
                  }}
                />
              </div>
              <span
                className="mt-1 text-[11px] leading-tight font-semibold transition-all duration-300"
                style={{ 
                  color: isActive ? '#ffffff' : '#4b5563',
                  textShadow: isActive ? '0 1px 2px rgba(0,0,0,0.3)' : 'none',
                  fontWeight: isActive ? 700 : 500
                }}
              >
                {item.label}
              </span>
              
              {/* Active indicator dot */}
              {isActive && (
                <div 
                  className="absolute -bottom-1 left-1/2 transform -translate-x-1/2 w-2 h-2 rounded-full animate-pulse"
                  style={{ background: '#ffffff', boxShadow: '0 0 8px rgba(255,255,255,0.8)' }}
                />
              )}
            </Link>
          );
        })}
      </div>
    </nav>
  );
};

export default BottomNavigation;
